-- Hook load & loadstring
local old_load = load
local old_loadstring = loadstring

load = function(code, ...)
    print("\n===== [LOAD DUMP] =====\n")
    print(code)
    print("\n===== [END] =====\n")
    return old_load(code, ...)
end

loadstring = function(code, ...)
    print("\n===== [LOADSTRING DUMP] =====\n")
    print(code)
    print("\n===== [END] =====\n")
    return old_loadstring(code, ...)
end

